// Email Detector - Extract all email addresses from OCR text
const items = $input.all();
const results = [];

// Email regex pattern with domain validation
const emailRegex = /\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b/g;

for (const item of items) {
  const text = item.json.text || '';
  const detectedEmails = [];

  let match;
  while ((match = emailRegex.exec(text)) !== null) {
    detectedEmails.push({
      value: match[0],
      type: 'email',
      start_pos: match.index,
      end_pos: match.index + match[0].length,
      confidence: 1.0
    });
  }

  results.push({
    json: {
      detections: detectedEmails,
      detector: 'email',
      original_text: text
    }
  });
}

return results;

// Phone number detection with country-aware patterns
const items = $input.all();
const results = [];

// Get the extracted text from OCR node
for (const item of items) {
  const text = item.json.text || '';

  // Comprehensive phone number patterns for various countries
  // Matches formats like: +1234567890, +1234567890, (555) 123-4567, etc.
  const phonePatterns = [
    // International format with country code
    /\+\d{1,3}[\s.-]?\(?\d{1,4}\)?[\s.-]?\d{1,4}[\s.-]?\d{1,4}[\s.-]?\d{1,9}/g,
    // US/Canada format with parentheses
    /\(?\d{3}\)?[\s.-]?\d{3}[\s.-]?\d{4}/g,
    // General format with separators
    /\d{3,4}[\s.-]\d{3,4}[\s.-]\d{3,4}/g
  ];

  const detectedPhones = [];
  const seenPhones = new Set();

  for (const pattern of phonePatterns) {
    let match;
    while ((match = pattern.exec(text)) !== null) {
      const phoneValue = match[0];

      // Avoid duplicates
      if (!seenPhones.has(phoneValue)) {
        seenPhones.add(phoneValue);

        detectedPhones.push({
          value: phoneValue,
          type: 'phone',
          start_pos: match.index,
          end_pos: match.index + phoneValue.length,
          confidence: 0.95
        });
      }
    }
  }

  // Return results for this item
  if (detectedPhones.length > 0) {
    results.push({
      json: {
        detected_pii: detectedPhones,
        original_text: text,
        detection_type: 'phone',
        count: detectedPhones.length
      }
    });
  }
}

// If no phones detected, return empty result
if (results.length === 0) {
  return [{
    json: {
      detected_pii: [],
      detection_type: 'phone',
      count: 0
    }
  }];
}

return results;

// ID Number Detector - Detects SSN, PAN, License Numbers, Bank Account Numbers
// Returns array of objects with value, type, start_pos, end_pos, confidence

const items = $input.all();
const results = [];

for (const item of items) {
  const text = item.json.extractedText || item.json.text || '';
  const detections = [];

  // SSN Pattern (XXX-XX-XXXX or XXXXXXXXX)
  const ssnPattern = /\b(?:\d{3}-\d{2}-\d{4}|\d{9})\b/g;
  let match;

  while ((match = ssnPattern.exec(text)) !== null) {
    const value = match[0];
    // Basic validation: not all zeros, not sequential
    const digits = value.replace(/-/g, '');
    if (digits !== '+1234567890' && digits !== '123456789') {
      detections.push({
        value: value,
        type: 'id_number',
        subtype: 'ssn',
        start_pos: match.index,
        end_pos: match.index + value.length,
        confidence: 0.9
      });
    }
  }

  // PAN (Permanent Account Number - India) Pattern (AAAAA9999A)
  const panPattern = /\b[A-Z]{5}[0-9]{4}[A-Z]\b/g;

  while ((match = panPattern.exec(text)) !== null) {
    const value = match[0];
    detections.push({
      value: value,
      type: 'id_number',
      subtype: 'pan',
      start_pos: match.index,
      end_pos: match.index + value.length,
      confidence: 0.9
    });
  }

  // Driver's License Pattern (varies by region, common formats)
  // US format: 1-2 letters followed by 6-8 digits
  const licensePattern = /\b[A-Z]{1,2}[0-9]{6,8}\b/g;

  while ((match = licensePattern.exec(text)) !== null) {
    const value = match[0];
    detections.push({
      value: value,
      type: 'id_number',
      subtype: 'drivers_license',
      start_pos: match.index,
      end_pos: match.index + value.length,
      confidence: 0.9
    });
  }

  // Bank Account Number Pattern (8-17 digits)
  const bankAccountPattern = /\b[0-9]{8,17}\b/g;

  while ((match = bankAccountPattern.exec(text)) !== null) {
    const value = match[0];
    // Avoid false positives by checking it's not already detected as SSN
    const isSSN = detections.some(d => d.subtype === 'ssn' && d.value.replace(/-/g, '') === value);
    if (!isSSN) {
      detections.push({
        value: value,
        type: 'id_number',
        subtype: 'bank_account',
        start_pos: match.index,
        end_pos: match.index + value.length,
        confidence: 0.9
      });
    }
  }

  // IBAN Pattern (International Bank Account Number)
  const ibanPattern = /\b[A-Z]{2}[0-9]{2}[A-Z0-9]{11,30}\b/g;

  while ((match = ibanPattern.exec(text)) !== null) {
    const value = match[0];
    detections.push({
      value: value,
      type: 'id_number',
      subtype: 'iban',
      start_pos: match.index,
      end_pos: match.index + value.length,
      confidence: 0.9
    });
  }

  results.push({
    json: {
      detections: detections,
      originalText: text,
      detectionCount: detections.length
    }
  });
}

return results;

// PII Consolidation & Conflict Resolver
// Merges all PII detections, resolves overlaps, deduplicates, and returns consolidated PII map

const allDetections = [];

// Collect all PII detections from all input items
for (const item of $input.all()) {
  if (item.json.detections && Array.isArray(item.json.detections)) {
    allDetections.push(...item.json.detections);
  }
}

console.log(`Total detections collected: ${allDetections.length}`);

// Sort detections by start position for easier overlap detection
allDetections.sort((a, b) => a.start - b.start);

// Resolve overlaps: higher confidence wins, longer span preferred if confidence is equal
const resolvedDetections = [];

for (const detection of allDetections) {
  let shouldAdd = true;
  let indexToReplace = -1;

  for (let i = 0; i < resolvedDetections.length; i++) {
    const existing = resolvedDetections[i];

    // Check for overlap
    const hasOverlap = (
      (detection.start >= existing.start && detection.start < existing.end) ||
      (detection.end > existing.start && detection.end <= existing.end) ||
      (detection.start <= existing.start && detection.end >= existing.end)
    );

    if (hasOverlap) {
      const detectionLength = detection.end - detection.start;
      const existingLength = existing.end - existing.start;

      // Higher confidence wins
      if (detection.confidence > existing.confidence) {
        indexToReplace = i;
        break;
      } else if (detection.confidence === existing.confidence) {
        // If confidence is equal, prefer longer span
        if (detectionLength > existingLength) {
          indexToReplace = i;
          break;
        } else {
          shouldAdd = false;
          break;
        }
      } else {
        shouldAdd = false;
        break;
      }
    }
  }

  if (indexToReplace >= 0) {
    resolvedDetections[indexToReplace] = detection;
  } else if (shouldAdd) {
    resolvedDetections.push(detection);
  }
}

console.log(`Detections after overlap resolution: ${resolvedDetections.length}`);

// Deduplicate exact matches (same type, value, and position)
const deduplicatedDetections = [];
const seen = new Set();

for (const detection of resolvedDetections) {
  const key = `${detection.type}|${detection.value}|${detection.start}|${detection.end}`;

  if (!seen.has(key)) {
    seen.add(key);
    deduplicatedDetections.push(detection);
  }
}

console.log(`Detections after deduplication: ${deduplicatedDetections.length}`);

// Create consolidated PII map
const piiMap = deduplicatedDetections.map((detection, index) => ({
  id: `pii_${index + 1}`,
  type: detection.type,
  value: detection.value,
  start: detection.start,
  end: detection.end,
  confidence: detection.confidence,
  source: detection.source || 'unknown'
}));

// Sort by start position for final output
piiMap.sort((a, b) => a.start - b.start);

return [
  {
    json: {
      piiMap: piiMap,
      totalDetections: piiMap.length,
      originalText: $input.first().json.extractedText || $input.first().json.text || '',
      timestamp: new Date().toISOString()
    }
  }
];

// Tokenization & Vault Storage
// Generates secure tokens for PII and prepares vault records

const items = $input.all();
const vaultRecords = [];
const tokenMap = {};

// Helper function to generate random hash
function generateHash(length = 4) {
  const chars = '0123456789ABCDEF';
  let hash = '';
  for (let i = 0; i < length; i++) {
    hash += chars.charAt(Math.floor(Math.random() * chars.length));
  }
  return hash;
}

// Process all PII items from consolidated data
for (const item of items) {
  const piiData = item.json.consolidatedPII || [];
  const originalText = item.json.originalText || '';
  const documentId = item.json.documentId || item.json.document_id || 'unknown';

  for (const pii of piiData) {
    const type = pii.type.toUpperCase();
    const originalValue = pii.value;
    const hash = generateHash(4);
    const token = `<<${type}_${hash}>>`;

    // Create vault record
    vaultRecords.push({
      token: token,
      original_value: originalValue,
      type: type,
      document_id: documentId,
      created_at: new Date().toISOString()
    });

    // Store token mapping for text replacement
    tokenMap[originalValue] = token;
  }
}

// Generate masked text by replacing all PII with tokens
let maskedText = items[0]?.json?.originalText || '';
for (const [originalValue, token] of Object.entries(tokenMap)) {
  // Use global replace to handle multiple occurrences
  const regex = new RegExp(originalValue.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'), 'g');
  maskedText = maskedText.replace(regex, token);
}

return [{
  json: {
    vaultRecords: vaultRecords,
    tokenMap: tokenMap,
    maskedText: maskedText,
    documentId: items[0]?.json?.documentId || items[0]?.json?.document_id || 'unknown',
    originalText: items[0]?.json?.originalText || '',
    totalTokensGenerated: vaultRecords.length
  }
}];

// Generate Masked Text - Replace PII with tokens
const items = $input.all();

if (items.length === 0) {
  return [{
    json: {
      masked_text: '',
      token_count: 0,
      masking_success: false,
      error: 'No input items'
    }
  }];
}

// Get the original text from OCR Extract Text node
const ocrData = $('OCR Extract Text').first().json;
let originalText = ocrData.text || '';

// Get the tokenized PII data from Store Tokens in Vault node
const vaultData = $('Store Tokens in Vault').all();

if (!vaultData || vaultData.length === 0) {
  return [{
    json: {
      masked_text: originalText,
      token_count: 0,
      masking_success: false,
      error: 'No tokenized data available'
    }
  }];
}

let maskedText = originalText;
let tokenCount = 0;
let allReplacementsSucceeded = true;
const replacements = [];

// Process each tokenized PII item
for (const item of vaultData) {
  const piiData = item.json;

  if (piiData.original_value && piiData.token) {
    const originalValue = piiData.original_value;
    const token = piiData.token;

    // Check if the original value exists in the text
    if (maskedText.includes(originalValue)) {
      // Replace all occurrences of the original value with the token
      const regex = new RegExp(originalValue.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'), 'g');
      const beforeLength = maskedText.length;
      maskedText = maskedText.replace(regex, token);
      const afterLength = maskedText.length;

      // Count successful replacements
      if (beforeLength !== afterLength || maskedText.includes(token)) {
        tokenCount++;
        replacements.push({
          original: originalValue,
          token: token,
          type: piiData.pii_type || 'unknown',
          replaced: true
        });
      } else {
        allReplacementsSucceeded = false;
        replacements.push({
          original: originalValue,
          token: token,
          type: piiData.pii_type || 'unknown',
          replaced: false
        });
      }
    } else {
      // Original value not found in text
      allReplacementsSucceeded = false;
      replacements.push({
        original: originalValue,
        token: token,
        type: piiData.pii_type || 'unknown',
        replaced: false,
        reason: 'Value not found in text'
      });
    }
  }
}

// Return the masked text with metadata
return [{
  json: {
    masked_text: maskedText,
    original_text: originalText,
    token_count: tokenCount,
    masking_success: allReplacementsSucceeded && tokenCount > 0,
    replacements: replacements,
    timestamp: new Date().toISOString()
  }
}];

