// Re-Injection Controller
// Analyzes AI output, identifies fields requiring PII restoration,
// extracts tokens, and prepares re-injection request

const items = $input.all();
const results = [];

for (const item of items) {
  const aiOutput = item.json.aiOutput || item.json;
  const fieldPermissions = item.json.fieldPermissions || {};
  const tokensToRetrieve = [];
  const reinjectionMap = {};

  // Define which fields should have PII restored based on permissions
  // Fields marked as 'restore' or 'unmask' will have original PII restored
  const fieldsToRestore = Object.keys(fieldPermissions).filter(
    field => fieldPermissions[field] === 'restore' || fieldPermissions[field] === 'unmask'
  );

  // Traverse AI output and identify token placeholders
  function extractTokens(obj, path = '') {
    for (const key in obj) {
      const currentPath = path ? `${path}.${key}` : key;
      const value = obj[key];

      if (typeof value === 'string') {
        // Check if value contains token pattern (e.g., TOKEN_EMAIL_123, TOKEN_PHONE_456)
        const tokenPattern = /TOKEN_([A-Z_]+)_([a-f0-9-]+)/g;
        const matches = value.matchAll(tokenPattern);

        for (const match of matches) {
          const fullToken = match[0];
          const tokenType = match[1];
          const tokenId = match[2];

          // Check if this field should be restored
          const shouldRestore = fieldsToRestore.some(field => 
            currentPath.includes(field) || key === field
          );

          if (shouldRestore) {
            tokensToRetrieve.push({
              token: fullToken,
              tokenId: tokenId,
              tokenType: tokenType,
              field: currentPath,
              originalValue: value
            });

            if (!reinjectionMap[currentPath]) {
              reinjectionMap[currentPath] = [];
            }
            reinjectionMap[currentPath].push(fullToken);
          }
        }
      } else if (typeof value === 'object' && value !== null) {
        extractTokens(value, currentPath);
      }
    }
  }

  extractTokens(aiOutput);

  // Prepare output with re-injection instructions
  results.push({
    json: {
      aiOutput: aiOutput,
      tokensToRetrieve: tokensToRetrieve,
      reinjectionMap: reinjectionMap,
      fieldPermissions: fieldPermissions,
      totalTokensFound: tokensToRetrieve.length,
      fieldsToRestore: fieldsToRestore,
      timestamp: new Date().toISOString(),
      workflowExecutionId: $execution.id
    }
  });
}

return results;

// Restore Original PII - Replace tokens with original values from vault
// Only restore PII for explicitly allowed fields based on re-injection policy

const aiOutput = $input.first().json;
const vaultData = $('Retrieve Original Values').all();

// Create a map of tokens to original values
const tokenMap = {};
vaultData.forEach(item => {
  const data = item.json;
  tokenMap[data.token] = {
    originalValue: data.original_value,
    piiType: data.pii_type,
    allowedForReinjection: data.allowed_for_reinjection
  };
});

// Function to recursively restore PII in objects
function restorePII(obj) {
  if (typeof obj === 'string') {
    // Check if string contains tokens (format: [TOKEN_xxxxx])
    const tokenRegex = /\[TOKEN_[A-Z0-9]+\]/g;
    return obj.replace(tokenRegex, (token) => {
      const tokenData = tokenMap[token];
      if (tokenData && tokenData.allowedForReinjection) {
        return tokenData.originalValue;
      }
      // Keep token if not allowed for re-injection
      return token;
    });
  } else if (Array.isArray(obj)) {
    return obj.map(item => restorePII(item));
  } else if (obj !== null && typeof obj === 'object') {
    const restored = {};
    for (const key in obj) {
      restored[key] = restorePII(obj[key]);
    }
    return restored;
  }
  return obj;
}

// Restore PII in the AI output
const restoredOutput = restorePII(aiOutput);

// Create audit trail
const restoredFields = [];
for (const token in tokenMap) {
  if (tokenMap[token].allowedForReinjection) {
    restoredFields.push({
      token: token,
      piiType: tokenMap[token].piiType
    });
  }
}

return [
  {
    json: {
      finalOutput: restoredOutput,
      restoredFields: restoredFields,
      restorationTimestamp: new Date().toISOString(),
      totalTokensRestored: restoredFields.length
    }
  }
];
